export interface IconProps extends ComponentProps<"svg"> {
  name: keyof typeof icons
  size?: "small" | "normal" | "medium" | "large"
  viewBox?: string
}

export function Icon(props: IconProps) {
  const [local, others] = splitProps(props, ["name", "size", "class", "classList", "viewBox"])
  const resolvedViewBox = () =>
    local.viewBox ?? (local.name.startsWith("tab-") ? "0 0 18 18"
      : local.name === "magnifying-glass" || local.name === "arrow-undo-down" ? "0 0 16 16"
      : "0 0 20 20")
  return (
    <div data-component="icon" data-size={local.size || "normal"}>
      <svg
        data-slot="icon-svg"
        classList={{
          ...local.classList,
          [local.class ?? ""]: !!local.class,
        }}
        fill="none"
        viewBox={resolvedViewBox()}
        innerHTML={icons[local.name as keyof typeof icons]}
        aria-hidden="true"
        {...others}
      />
    </div>
  )
}
